// FILE: excel_file.jsx
import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function ExcelUpload() {
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [excelData, setExcelData] = useState([]);
  const navigate = useNavigate();

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    setFile(selectedFile);
    setMessage('');
    setExcelData([]);

    const reader = new FileReader();
    reader.onload = (evt) => {
      const bstr = evt.target.result;
      const workbook = XLSX.read(bstr, { type: 'binary' });
      const worksheetName = workbook.SheetNames[0];
      const worksheet = workbook.Sheets[worksheetName];
      const data = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
      setExcelData(data);
    };
    reader.readAsBinaryString(selectedFile);
  };

  const handleUpload = async () => {
    if (!file) {
      return setMessage('❌ Please select an Excel file to upload.');
    }

    const formData = new FormData();
    formData.append('excel', file);

    try {
      setLoading(true);
      setMessage('');
      await axios.post('http://localhost:3000/api/questions/upload-excel', formData);
      setMessage('✅ Excel file uploaded successfully!');
      setFile(null);
    } catch (err) {
      console.error('❌ Upload failed:', err);
      setMessage(`❌ Upload failed: ${err.response?.data?.message || err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl p-6 mx-auto mt-10 bg-white rounded shadow-lg">
      <h2 className="mb-4 text-2xl font-bold text-gray-800">Upload Excel File</h2>
      <input
        type="file"
        accept=".xlsx,.xls"
        onChange={handleFileChange}
        className="block w-full mb-4 text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
      />
      <div className="flex gap-4">
        <button
          onClick={handleUpload}
          disabled={loading}
          className="flex-1 px-4 py-2 text-white bg-indigo-600 rounded hover:bg-indigo-700 disabled:bg-gray-400"
        >
          {loading ? 'Uploading...' : 'Upload'}
        </button>
        <button
          onClick={() => navigate(-1)}
          className="flex-1 px-4 py-2 text-gray-700 bg-gray-100 border border-gray-300 rounded hover:bg-gray-200"
        >
          Go Back
        </button>
      </div>
      {message && <p className="mt-4 text-sm text-center text-gray-700">{message}</p>}

      {excelData.length > 0 && (
        <div className="pt-4 mt-6 overflow-x-auto border-t">
          <h3 className="mb-2 text-lg font-semibold text-gray-700">Excel Preview</h3>
          <table className="w-full text-sm text-left border">
            <thead className="bg-gray-100">
              <tr>
                {excelData[0].map((header, i) => (
                  <th key={i} className="px-4 py-2 border">
                    {header}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {excelData.slice(1).map((row, rowIndex) => (
                <tr key={rowIndex} className="hover:bg-gray-50">
                  {row.map((cell, cellIndex) => (
                    <td key={cellIndex} className="px-4 py-2 border">
                      {cell}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
